import React from 'react';
import './index.css';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import AiAssistant from './components/AiAssistant';

import AuthorityPage from './pages/Authority';
import BinPage from './pages/Bin';
import DriverPage from './pages/Driver';
import UserPage from './pages/User';
import VehiclePage from './pages/Vehicle';

function App() {
  return (
    <Router>
      {/* GLOBAL APP BACKGROUND */}
      <div className="app-root">
        <Navbar />

        {/* PAGE CONTAINER – SAME FOR ALL PAGES */}
        <main className="app-container">
          <Routes>
            {/* HOME */}
            <Route
              path="/"
              element={
                <div className="home-wrapper">
                  <div className="home-card">
                    <div className="home-icon">♻️</div>
                    <h1 className="home-title">
                      Smart Waste Management System
                    </h1>
                    <p className="home-subtitle">
                      🌱 Efficient & Eco-Friendly Waste Collection Operations
                    </p>

                    <div className="home-grid">
                      <HomeFeature icon="🏛️" title="Authority" />
                      <HomeFeature icon="🚛" title="Driver" />
                      <HomeFeature icon="🚜" title="Vehicle" />
                      <HomeFeature icon="🗑️" title="Smart Bin" />
                      <HomeFeature icon="👥" title="User" />
                    </div>
                  </div>
                </div>
              }
            />

            <Route path="/authority" element={<AuthorityPage />} />
            <Route path="/bin" element={<BinPage />} />
            <Route path="/driver" element={<DriverPage />} />
            <Route path="/user" element={<UserPage />} />
            <Route path="/vehicle" element={<VehiclePage />} />
          </Routes>
        </main>

        <AiAssistant />
      </div>
    </Router>
  );
}

function HomeFeature({ icon, title }) {
  return (
    <div className="home-feature">
      <div className="home-feature-icon">{icon}</div>
      <h4>{title}</h4>
    </div>
  );
}

export default App;
